// Build ref_code + map private fields. Default consent_public=false.
const r = $json;
const year = new Date().getFullYear();
const seq = String(($json.row_number||0)).padStart(3,'0');
const ref = `NIS-${year}-${seq}`;
return [{ json: {
  ref_code: ref,
  full_name: r['Full name'],
  location: r['Location'],
  category: r['Category'],
  needs: r['Needs'],
  story_private: r['Case notes'],
  consent_public: (r['Consent to share'] === 'Yes'),
  consent_photo: (r['Consent to photo'] === 'Yes'),
  public_name: r['Preferred display name'] || null
}}];
